ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT (AVG(?diff) AS ?a) WHERE { ?t a :Tickets ; p:seat_number ?sn ; p:hasPre_sale_Date ?ps . ?ps p:start_time ?st ; p:end_time ?et . BIND(xsd:integer(SUBSTR(STR(?et),1,2)) - xsd:integer(SUBSTR(STR(?st),1,2)) AS ?diff) FILTER(STR(?sn)="A1") } }
  full: { SELECT (AVG(?pd) AS ?pavg) (AVG(?od) AS ?oavg) WHERE { ?t a :Tickets ; p:seat_number ?sn ; p:hasPre_sale_Date ?ps ; p:hasOn_Sale_Date ?os . ?ps p:start_time ?pst ; p:end_time ?pet . ?os p:start_time ?ost ; p:end_time ?oet . BIND(xsd:integer(SUBSTR(STR(?pet),1,2)) - xsd:integer(SUBSTR(STR(?pst),1,2)) AS ?pd) BIND(xsd:integer(SUBSTR(STR(?oet),1,2)) - xsd:integer(SUBSTR(STR(?ost),1,2)) AS ?od) FILTER(STR(?sn)="A1") } }
  component_2: { SELECT (AVG(?diff) AS ?a) WHERE { ?t a :Tickets ; p:seat_number ?sn ; p:hasOn_Sale_Date ?os . ?os p:start_time ?st ; p:end_time ?et . BIND(xsd:integer(SUBSTR(STR(?et),1,2)) - xsd:integer(SUBSTR(STR(?st),1,2)) AS ?diff) FILTER(STR(?sn)="A1") } }
}
